// n8n Function node
// Payload comes from Webhook node

const payload = items[0].json.body;
const dmId = $input.first().json.body.chat_id
// ---- Extract required fields ----
const senderName = payload.sender?.attendee_name ?? null;
const messageText = payload.message ?? null;
const accountId = payload.account_id ?? null;
const dmTimestamp = payload.timestamp ?? null;

// ---- Validate presence ----
if (!senderName || !messageText || !dmTimestamp) {
  throw new Error("Missing required LinkedIn DM fields");
}


return [
  {
    json: {
      dm_id: dmId,
      sender_name: senderName,
      message_text: messageText,
      account_id: accountId,
      dm_timestamp: dmTimestamp
    }
  }
];

