const body = $input.first().json.body;
const payload = JSON.parse(body.payload);
const messageBlocks = payload.message.blocks;
const sectionText = messageBlocks[0].text.text;

// 1. Extract first_dm_time from the message text
const timeRegex = /\*first_dm_time:\*\s*([^\n]+)/;
const timeMatch = sectionText.match(timeRegex);
const firstDmTime = timeMatch ? timeMatch[1].trim() : null;

// 2. Parse custom button values (dm_id and record_id)
const buttonValue = JSON.parse(payload.actions[0].value);

// 3. Calculate Response Time in Minutes
const start = new Date(firstDmTime);
const end = new Date(); // This is the current "responded_at" time
const diffMs = end - start;
const diffMins = Math.round(diffMs / 60000);

// 4. Extract and clean the action name (dm_responded -> responded)
const rawAction = payload.actions[0].action_id;
const actionText = rawAction.replace('dm_', '');

return {
  trigger_id: payload.trigger_id,
  dm_id: buttonValue.dm_id,
  record_id: buttonValue.record_id,
  action: actionText,
  assignee: payload.user.name,
  first_dm_time: firstDmTime,
  responded_at: end.toISOString(), // The requested field
  response_time: diffMins,
  response_url: payload.response_url,
  thread_ts: payload.container.message_ts // Required for thread reply
};
